import React, { useState } from "react";
import SalesForm from "../components/SalesForm";
import StockTable from "../components/StockTable";
import Alerts from "../components/Alerts";
import Analytics from "../components/Analytics";
import InventoryPie from "../components/InventoryPie";


function Dashboard() {

  const [analytics, setAnalytics] = useState([]);

  const [stock, setStock] = useState([
    { name: "Milk", quantity: 20, expiry: "2026-01-10" },
    { name: "Maggi", quantity: 40, expiry: "2026-03-01" },
  ]);

  const addSale = (itemName, soldQty) => {
    const updatedStock = stock.map((item) =>
      item.name === itemName
        ? { ...item, quantity: item.quantity - soldQty }
        : item
    );
    setStock(updatedStock);
  };

  return (
    <div className="container">
      <div className="card">
        <SalesForm addSale={addSale} />
      </div>

      <div className="card">
        <StockTable stock={stock} />
      </div>

      <div className="card">
        <Alerts stock={stock} />
      </div>

      <div className="card">
        <Analytics analytics={analytics} />
      </div>
    </div>
  );
}

export default Dashboard;
